def _sapbw_info_object_to_nested(
    sapbw_info_object: SAPBWInfoObject,
) -> SAPBWInfoObjectNested:
    """Convert flat SAPBWInfoObject to nested format."""
    attrs = SAPBWInfoObjectAttributes()
    _populate_sapbw_info_object_attrs(attrs, sapbw_info_object)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        sapbw_info_object,
        _SAPBW_INFO_OBJECT_REL_FIELDS,
        SAPBWInfoObjectRelationshipAttributes,
    )
    return SAPBWInfoObjectNested(
        guid=sapbw_info_object.guid,
        type_name=sapbw_info_object.type_name,
        status=sapbw_info_object.status,
        version=sapbw_info_object.version,
        create_time=sapbw_info_object.create_time,
        update_time=sapbw_info_object.update_time,
        created_by=sapbw_info_object.created_by,
        updated_by=sapbw_info_object.updated_by,
        classifications=sapbw_info_object.classifications,
        classification_names=sapbw_info_object.classification_names,
        meanings=sapbw_info_object.meanings,
        labels=sapbw_info_object.labels,
        business_attributes=sapbw_info_object.business_attributes,
        custom_attributes=sapbw_info_object.custom_attributes,
        pending_tasks=sapbw_info_object.pending_tasks,
        proxy=sapbw_info_object.proxy,
        is_incomplete=sapbw_info_object.is_incomplete,
        provenance_type=sapbw_info_object.provenance_type,
        home_id=sapbw_info_object.home_id,
        depth=sapbw_info_object.depth,
        immediate_upstream=sapbw_info_object.immediate_upstream,
        immediate_downstream=sapbw_info_object.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _sapbw_info_object_from_nested(nested: SAPBWInfoObjectNested) -> SAPBWInfoObject:
    """Convert nested format to flat SAPBWInfoObject."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else SAPBWInfoObjectAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SAPBW_INFO_OBJECT_REL_FIELDS,
        SAPBWInfoObjectRelationshipAttributes,
    )
    return SAPBWInfoObject(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_sapbw_info_object_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _sapbw_info_object_to_nested_bytes(
    sapbw_info_object: SAPBWInfoObject, serde: Serde
) -> bytes:
    """Convert flat SAPBWInfoObject to nested JSON bytes."""
    return serde.encode(_sapbw_info_object_to_nested(sapbw_info_object))


def _sapbw_info_object_from_nested_bytes(data: bytes, serde: Serde) -> SAPBWInfoObject:
    """Convert nested JSON bytes to flat SAPBWInfoObject."""
    nested = serde.decode(data, SAPBWInfoObjectNested)
    return _sapbw_info_object_from_nested(nested)


